module top_module (
  input clk,
  input reset,
  input load,
  input [7:0] data_in,
  output reg data_out);

reg [7:0] unused_shift_reg;

always @(posedge clk or posedge reset) begin
    if (reset)
        unused_shift_reg <= 8'b00000000;
    else if (load)
        unused_shift_reg <= data_in;
    else
        unused_shift_reg <= {unused_shift_reg[6:0], 1'b0};
end

always @(unused_shift_reg)
    data_out = unused_shift_reg[7];
endmodule
